                <input class="form-check-input darker-border-checkbox"
                       type="checkbox"
                       id="@($"ch-{channel}")"
                       checked="@_mutedChannels.Contains(channel)"
                       @onchange="e => ToggleMutedChannel(channel, (bool)e.Value!)" />
                <label class="form-check-label" for="@($"ch-{channel}")">
                    #@channel
                </label>
            </div>
