@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _allChannels = prefs.MutedChannels.ToList();
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleMutedChannel(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        _saving = true;
        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList()
        );
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        await ShowToast("Notification preferences saved!");
    }

    private async Task ShowToast(string message)
    {
        _toastMessage = message;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

@using sv_2d8ec8e889b74c1da689f4f7fd43e303.Services
@inject ISettingsService SettingsService

<div class="section-header">
    <h3>Security</h3>
    <p>Manage your account security</p>
</div>

@if (_loading)
{
    <p>Loading security settings…</p>
}
else
{
    @if (_toastMessage is not null)
    {
        <div class="toast-message @_toastClass">@_toastMessage</div>
    }

    @* Change Password *@
    <div class="settings-card">
        <div class="expand-toggle" @onclick="() => _passwordExpanded = !_passwordExpanded">
            <h5 class="mb-0">Change Password</h5>
            <span class="arrow @(_passwordExpanded ? "open" : "")">▶</span>
        </div>

        @if (_passwordExpanded)
        {
            <div class="mt-3">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Current Password</label>
                    <input type="password" class="form-control" @bind="_currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">New Password</label>
                    <input type="password" class="form-control" @bind="_newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Confirm New Password</label>
                    <input type="password" class="form-control" @bind="_confirmPassword" />
                </div>

                @if (_passwordError is not null)
                {
                    <div class="text-danger mb-2" style="font-size:0.9rem;">@_passwordError</div>
                }

                <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_changingPassword">
                    @(_changingPassword ? "Updating…" : "Update Password")
                </button>

                @if (_lastPasswordChange.HasValue)
                {
                    <div class="text-muted mt-2" style="font-size:0.85rem;">
                        Last changed: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
                    </div>
                }
            </div>
        }
    </div>

    @* Two-Factor Authentication *@
    <div class="settings-card">
        <div class="d-flex align-items-center justify-content-between">
            <div>
                <h5 class="mb-1">Two-Factor Authentication</h5>
                <span class="status-badge @(_twoFactorEnabled ? "status-enabled" : "status-disabled")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch"
                       checked="@_twoFactorEnabled"
                       @onchange="e => _twoFactorEnabled = (bool)e.Value!" />
            </div>
        </div>
    </div>

    @* Active Sessions *@
    <div class="settings-card">
        <h5>Active Sessions</h5>
        @if (_sessions.Count == 0)
        {
            <p class="text-muted">No active sessions.</p>
        }
        else
        {
            <table class="sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != _currentSessionId)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        }
    </div>

    @* Revoke Confirmation Dialog *@
    @if (_sessionToRevoke is not null)
    {
        <div class="confirm-overlay" @onclick="CancelRevoke">
            <div class="confirm-dialog" @onclick:stopPropagation>
                <h5>Revoke Session</h5>
                <p>
                    Are you sure you want to revoke the session on
                    <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?
                </p>
                <div class="btn-group-end">
                    <button class="btn btn-outline-secondary btn-sm" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger btn-sm" @onclick="ConfirmRevoke" disabled="@_revoking">
                        @(_revoking ? "Revoking…" : "Revoke")
                    </button>
                </div>
            </div>
        </div>
    }
}

@code {
    private bool _loading = true;
    private string? _toastMessage;
    private string _toastClass = "toast-success";

    // Password
    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _changingPassword;
    private DateTime? _lastPasswordChange;

    // 2FA
    private bool _twoFactorEnabled;

    // Sessions
    private List<ActiveSession> _sessions = [];
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;
    private const string _currentSessionId = "session-1";

    protected override async Task OnInitializedAsync()
    {
        var security = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = security.TwoFactorEnabled;
        _lastPasswordChange = security.LastPasswordChange;
        _sessions = security.Sessions.ToList();
        _loading = false;
    }

    private async Task UpdatePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _changingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _lastPasswordChange = DateTime.UtcNow;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changingPassword = false;
        await ShowToast("Password updated successfully!", "toast-success");
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;

    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
        _revoking = false;
        _sessionToRevoke = null;
        await ShowToast("Session revoked.", "toast-success");
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private async Task ShowToast(string message, string cssClass)
    {
        _toastMessage = message;
        _toastClass = cssClass;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

