@using sv_2d8ec8e889b74c1da689f4f7fd43e303.Services
@inject ISettingsService SettingsService

<div class="section-header">
    <h3>Notifications</h3>
    <p>Control how you receive updates</p>
</div>

@if (_loading)
{
    <p>Loading notification preferences…</p>
}
else
{
    @if (_toastMessage is not null)
    {
        <div class="toast-message toast-success">@_toastMessage</div>
    }

    <div class="settings-card">
        <h5>Notification Channels</h5>

        <div class="toggle-row">
            <div>
                <div class="toggle-label">Email Notifications</div>
                <div class="toggle-desc">Receive notifications via email</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" @bind="_emailNotifications" />
            </div>
        </div>

        <div class="toggle-row">
            <div>
                <div class="toggle-label">Push Notifications</div>
                <div class="toggle-desc">Receive browser push notifications</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" @bind="_pushNotifications" />
            </div>
        </div>

        <div class="toggle-row">
            <div>
                <div class="toggle-label">Weekly Digest</div>
                <div class="toggle-desc">Get a weekly summary of activity</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" @bind="_weeklyDigest" />
            </div>
        </div>
    </div>

    <div class="settings-card">
        <h5>Muted Channels</h5>
        <p class="text-muted" style="font-size:0.85rem;">Uncheck channels you want to receive notifications from.</p>

        @foreach (var channel in _allChannels)
        {
            <div class="form-check mb-2">
                <input class="form-check-input darker-border-checkbox"
                       type="checkbox"
                       id="@($"ch-{channel}")"
                       checked="@_mutedChannels.Contains(channel)"
                       @onchange="e => ToggleMutedChannel(channel, (bool)e.Value!)" />
                <label class="form-check-label" for="@($"ch-{channel}")">
                    #@channel
                </label>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="SavePreferences" disabled="@_saving">
        @(_saving ? "Saving…" : "Save Preferences")
    </button>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _allChannels = prefs.MutedChannels.ToList();
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleMutedChannel(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        _saving = true;
        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList()
        );
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        await ShowToast("Notification preferences saved!");
    }

    private async Task ShowToast(string message)
    {
        _toastMessage = message;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

