else
{
    @if (_toastMessage is not null)
    {
        <div class="toast-message toast-success">@_toastMessage</div>
    }

    <div class="settings-card">
        <h5>Theme</h5>
        <div class="d-flex gap-3">
            @foreach (var theme in _themes)
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="theme"
                           id="@($"theme-{theme}")"
                           value="@theme"
                           checked="@(_theme == theme)"
                           @onchange="() => _theme = theme" />
                    <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                </div>
            }
        </div>
    </div>

    <div class="settings-card">
        <h5>Font Size</h5>
        <div class="d-flex gap-3">
            @foreach (var size in _fontSizes)
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="fontSize"
                           id="@($"fs-{size}")"
                           value="@size"
                           checked="@(_fontSize == size)"
                           @onchange="() => _fontSize = size" />
                    <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                </div>
            }
        </div>
    </div>

    <div class="settings-card">
        <h5>Language</h5>
        <select class="form-select" style="max-width: 250px;" @bind="_language">
            @foreach (var lang in _languages)
            {
                <option value="@lang">@lang</option>
            }
        </select>
    </div>

    <div class="settings-card">
        <div class="toggle-row" style="border:none;">
            <div>
                <div class="toggle-label">Compact Mode</div>
                <div class="toggle-desc">Reduce spacing and padding throughout the UI</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch" @bind="_compactMode" />
            </div>
        </div>
    </div>

    @* Live Preview *@
    <div class="settings-card">
        <h5>Preview</h5>
        <div class="preview-area" style="@PreviewStyle">
            <h4 style="margin-top:0;">Sample Heading</h4>
            <p>This is a preview of your selected appearance settings.</p>
            <button class="btn btn-primary btn-sm">Sample Button</button>
            <span class="badge bg-secondary ms-2">Badge</span>
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
        @(_saving ? "Saving…" : "Save")
    </button>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private string PreviewStyle
    {
        get
        {
            var bg = _theme switch
            {
                "Dark" => "background:#1e1e2e; color:#cdd6f4;",
                "System" => "background:#e9ecef; color:#333;",
                _ => "background:#ffffff; color:#212529;"
            };

            var fs = _fontSize switch
            {
                "Small" => "font-size:0.8rem;",
                "Large" => "font-size:1.15rem;",
                _ => "font-size:0.95rem;"
            };

            var padding = _compactMode ? "padding:0.75rem;" : "padding:1.5rem;";

            return $"{bg} {fs} {padding}";
        }
    }

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        await SettingsService.SaveAppearanceAsync(
            new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _saving = false;
        await ShowToast("Appearance settings saved!");
    }

    private async Task ShowToast(string message)
    {
        _toastMessage = message;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

